#!/usr/bin/env bash
# game-table-site-selection-bankro.sh — 赛前准备：game/table/site selection + bankroll check（开打前的元决策） SOP walkthrough for 德州扑克策略.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="德州扑克策略"
WORKFLOW="赛前准备：game/table/site selection + bankroll check（开打前的元决策）"

usage() {
  cat <<EOF
game-table-site-selection-bankro.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./game-table-site-selection-bankro.sh             # interactive
  ./game-table-site-selection-bankro.sh --dry-run
  ./game-table-site-selection-bankro.sh --json
  ./game-table-site-selection-bankro.sh --explain
  ./game-table-site-selection-bankro.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "赛前准备：game/table/site selection + bankroll check（开打前的元决策）" 工作流。

一句话: 从「想打牌」到「在最有利的牌房 / 牌桌 / 座位、且资金允许的前提下坐下」——开打前决定大半胜负的元决策。 (evidence: [T03-S026, T03-S025])

入门 SOP 共 4 步, 失败模式自检 3 项。

相关心智模型:
  • GTO 基线 ⇄ 剥削偏离(equilibrium baseline ⇄ exploitative deviation): 先建一条**不可剥削的均衡基线 (GTO)**,再针对具体对手/人群的可观察漏洞**偏离 (exploit)** 去最大化 EV;GTO 是回得去的**锚点**,不是终点。
  • Range-first(先想范围,再想这手牌): 扑克决策的**原子单位是范围(对手在某节点所有可能持牌的概率分布)**,不是单张牌;高手把对手 put on a *range* 再随每条街的行动收窄。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**bankroll 准入检查**:确认当前级别的 buy-in 数达标(见 workflow 5),不够则降级或不打。 (evidence: [T03-S018, T03-S017])"
  "**game / site selection**:选玩家更弱 / rake 更低的游戏与牌房(rake 直接侵蚀边际 winrate)。 (evidence: [T03-S026, T03-S025])"
  "**table selection**:挑有弱玩家(高 VPIP / 大 stack 娱乐玩家)、平均筹码深的桌。 (evidence: [T03-S026])"
  "**seat selection**:尽量坐在「钱(弱玩家 / 深筹激进者)的左边」,获得位置信息优势。 (evidence: [T03-S026])"
)
declare -a FAILURE_MODES=(
  "**忽视 game selection 死磕打法**:花几百小时学 solver 却总坐 reg 桌 → winrate 被 rake + 强对手吃掉。**避免**:把「换好桌」当首要杠杆,每 session 先选场再坐下。 (evidence: [T03-S026])"
  "**bankroll 不够硬冲级别**:为面子打超出资金的级别,一次下风期破产。**避免**:开打前过 buy-in 准入门槛,不够就降级(workflow 5)。 (evidence: [T03-S017])"
  "**在 C-game 状态坐硬桌**:疲劳/上头还选了高难度对局 → 把劣势状态送进最不该打的场。**避免**:开打前过状态 check(workflow 6),状态差就打软桌或不打。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "game-table-site-selection-bankro-walkthrough"
fi
